#ifndef ESEC_ARIA_BASICS_HEADER
#define ESEC_ARIA_BASICS_HEADER

#include <stdint.h>
#include <stddef.h>

#include "esec_errors.h"
#include "esec_symm_basics.h"

/** Size of the IV for ARIA */
#define ESEC_ARIA_IV_SIZE 16

/** Size of the IV for ARIA - GCM */
#define ESEC_ARIA_GCM_IV_SIZE 12

/* Block size for ARIA algorithms. */
#define ESEC_ARIA_BLOCK_SIZE 16

/** Size of the authentication tag generated by the ARIA GCM algorithm */
#define ESEC_TAG_SIZE_ARIA_GCM 16

/** Size of context generated while doing context switching in GCM/CCM mode */
#define ESEC_ARIA_CTX_xCM_SIZE 32

/** Maximum size of the authentication tag generated by the ARIA CCM algorithm */
#define ESEC_MAX_TAG_SIZE_ARIA_CCM 16

/** Size of the authentication tag generated by the ARIA CMAC algorithm
 *  Currently we support only 16 bytes MAC */
#define ESEC_TAG_SIZE_ARIA_CMAC 16

enum esec_aria_mode {
    ESEC_ARIA_ECB = 0x01,
    ESEC_ARIA_CBC = 0x02,
    ESEC_ARIA_CTR = 0x03,
    ESEC_ARIA_CFB = 0x04,
    ESEC_ARIA_OFB = 0x05,
};

struct esec_aria_state {
    /* Stores the eSecure command. */
    uint32_t command;
    /* Saved context between several calls. */
    uint8_t context[16];
    /* Saved key. */
    struct esec_skey skey;
};

#endif
